import assert from "node:assert/strict";
import test from "node:test";
import { loadConfig } from "../../src/config.ts";
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";

test("loadConfig returns defaults when no config file exists", () => {
	const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-lsp-test-"));
	try {
		const { config } = loadConfig(dir);
		assert.equal(config.enabled, true);
		assert.equal(config.autoStart, true);
		assert.equal(config.idleTimeoutMs, 300_000);
		assert.equal(config.syncContent, true);
		assert.equal(config.autoDiagnostics, true);
		assert.deepStrictEqual(config.servers, {});
		assert.deepStrictEqual(config.customServers, []);
	} finally {
		fs.rmSync(dir, { recursive: true });
	}
});

test("loadConfig reads .pi/pi-lsp.json", () => {
	const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-lsp-test-"));
	try {
		fs.mkdirSync(path.join(dir, ".pi"), { recursive: true });
		fs.writeFileSync(path.join(dir, ".pi", "pi-lsp.json"), JSON.stringify({
			enabled: false,
			idleTimeoutMs: 60_000,
			autoDiagnostics: false,
		}));
		const { config } = loadConfig(dir);
		assert.equal(config.enabled, false);
		assert.equal(config.idleTimeoutMs, 60_000);
		assert.equal(config.autoDiagnostics, false);
		// Defaults preserved
		assert.equal(config.autoStart, true);
		assert.equal(config.syncContent, true);
	} finally {
		fs.rmSync(dir, { recursive: true });
	}
});

test("loadConfig handles malformed JSON gracefully", () => {
	const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-lsp-test-"));
	try {
		fs.mkdirSync(path.join(dir, ".pi"), { recursive: true });
		fs.writeFileSync(path.join(dir, ".pi", "pi-lsp.json"), "not json {{{");
		const { config } = loadConfig(dir);
		// Should return defaults
		assert.equal(config.enabled, true);
	} finally {
		fs.rmSync(dir, { recursive: true });
	}
});

test("loadConfig validates customServers", () => {
	const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-lsp-test-"));
	try {
		fs.mkdirSync(path.join(dir, ".pi"), { recursive: true });
		fs.writeFileSync(path.join(dir, ".pi", "pi-lsp.json"), JSON.stringify({
			customServers: [
				{ language: "java", command: ["jdtls"], extensions: [".java"] },
				{ invalid: true },  // should be filtered
				"not an object",     // should be filtered
			],
		}));
		const { config } = loadConfig(dir);
		assert.equal(config.customServers.length, 1);
		assert.equal(config.customServers[0]!.language, "java");
	} finally {
		fs.rmSync(dir, { recursive: true });
	}
});
